import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("empty grid stays empty -- [] -> []");
  it.todo("single cell dies (underpopulation) -- [(0,0)] -> []");
  it.todo("two adjacent cells both die (underpopulation, 1 neighbor each) -- [(0,1),(1,1)] -> []");
  it.todo("block still life remains unchanged -- [(0,0),(1,0),(0,1),(1,1)] -> same");
  it.todo("live cell with 4 neighbors dies (overpopulation) -- center of full 3x3 dies");
  it.todo("dead cell with exactly 3 live neighbors becomes alive (reproduction) -- L-shape produces block");
  it.todo("blinker oscillates vertical -> horizontal -- [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]");
  it.todo("handles negative coordinates -- blinker centered at origin oscillates");
});

export type Cell = [number, number];

export function nextGeneration(_cells: Cell[]): Cell[] {
  throw new Error("not implemented");
}

