export type Cell = [number, number];

const key = (x: number, y: number): string => `${x},${y}`;

export function nextGeneration(currentGeneration: Cell[]): Cell[] {
  const liveCells = new Set(currentGeneration.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of currentGeneration) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const nextGen: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const isAlive = liveCells.has(k);
    if ((isAlive && (count === 2 || count === 3)) || (!isAlive && count === 3)) {
      const [xStr, yStr] = k.split(",");
      nextGen.push([Number(xStr), Number(yStr)]);
    }
  }

  return nextGen;
}

